// Pattern n8n : fix préfixe = dans callback data
const raw = $input.first().json.callback_query.data.replace(/^=/, '');

// Ne traiter que les callbacks auto_
if (!raw.startsWith('auto_')) {
  return [];
}

const parts = raw.split('_');
const sessionId = parseInt(parts[1]);

return [{
  json: {
    analysis_type: 'auto',
    session_id: sessionId,
    chat_id: $input.first().json.callback_query.message.chat.id,
    telegram_id: $input.first().json.callback_query.from.id,
    message_id: $input.first().json.callback_query.message.message_id
  }
}];

const row = $input.first().json;
const callbackData = $('Extract Callback Data').item.json;

// Parse extracted_data (stocké en JSONB, retourné comme text)
let extractedData = {};
try {
  const raw = row.extracted_data_raw || '{}';
  extractedData = typeof raw === 'object' ? raw : JSON.parse(raw);
} catch(e) {
  extractedData = { content_type: 'document', text: '' };
}

const lang = row.language || 'FR';
const fileName = row.file_name || 'fichier';
const fileType = row.file_type || 'unknown';
const contentType = extractedData.content_type || 'document';

let userPrompt = '';

if (contentType === 'data') {
  const dataStr = JSON.stringify({
    columns: extractedData.columns || [],
    sample_data: (extractedData.data || []).slice(0, 50),
    total_rows: extractedData.total_rows || 0
  });
  userPrompt = 'Analyse ce dataset et produis un rapport complet.\n\nDONNÉES :\n' + dataStr + '\n\nFICHIER : ' + fileName + ' (' + fileType.toUpperCase() + ')\nLANGUE : ' + (lang === 'FR' ? 'Français' : 'English') + '\n\nFORMAT REQUIS (JSON pur, sans markdown, sans texte avant/après) :\n{\n  "executive_summary": "3-4 phrases synthétiques",\n  "overview": {"rows": N, "columns": N, "data_quality": "X/10"},\n  "key_findings": ["finding 1", "finding 2", "finding 3"],\n  "detections": {"trends": [], "anomalies": [], "correlations": []},\n  "charts": [{"type": "bar", "title": "titre", "x": "colonne_x", "y": "colonne_y", "insight": "explication"}],\n  "recommendations": ["reco 1", "reco 2"]\n}';
} else {
  const text = (extractedData.text || '').substring(0, 8000);
  userPrompt = 'Analyse ce document et produis un rapport structuré.\n\nDOCUMENT :\n' + text + '\n\nFICHIER : ' + fileName + ' (' + fileType.toUpperCase() + ')\nLANGUE : ' + (lang === 'FR' ? 'Français' : 'English') + '\n\nFORMAT REQUIS (JSON pur, sans markdown, sans texte avant/après) :\n{\n  "executive_summary": "3-4 phrases",\n  "key_points": ["point 1", "point 2", "point 3"],\n  "insights": ["insight 1", "insight 2"],\n  "document_type": "type détecté",\n  "target_audience": "public cible",\n  "quality_score": "X/10",\n  "recommendations": ["reco 1"]\n}';
}

return [{
  json: {
    session_id: row.id || callbackData.session_id,
    chat_id: row.chat_id || callbackData.chat_id,
    telegram_id: row.telegram_id || callbackData.telegram_id,
    language: lang,
    file_name: fileName,
    file_type: fileType,
    content_type: contentType,
    extracted_data: extractedData,
    user_prompt: userPrompt,
    start_time: Date.now()
  }
}];

const agentOutput = $input.first().json;
const metadata = $('Prepare Agent Input').item.json;
const rawOutput = agentOutput.output || '';
const responseTimeMs = Date.now() - metadata.start_time;

let analysis = null;
try {
  let clean = rawOutput.trim();
  // Supprimer blocs markdown si présents
  if (clean.startsWith('```')) {
    clean = clean.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
  }
  // Extraire le JSON entre { et }
  const jsonStart = clean.indexOf('{');
  const jsonEnd = clean.lastIndexOf('}');
  if (jsonStart !== -1 && jsonEnd !== -1) {
    clean = clean.substring(jsonStart, jsonEnd + 1);
  }
  analysis = JSON.parse(clean);
} catch(e) {
  analysis = {
    executive_summary: rawOutput.substring(0, 500) || 'Analyse non disponible',
    key_findings: ['Erreur parsing JSON — vérifier le modèle IA'],
    parse_error: true
  };
}

return [{
  json: {
    ...metadata,
    analysis: analysis,
    response_time_ms: responseTimeMs,
    llm_used: 'grok',
    parse_success: !analysis.parse_error
  }
}];

const d = $input.first().json;
const r = d.analysis;
const isFR = d.language === 'FR';
let message = '';

if (d.content_type === 'data') {
  const header = isFR ? '📊 *RAPPORT D'ANALYSE*' : '📊 *ANALYSIS REPORT*';
  const overview = r.overview || {};
  const findings = (r.key_findings || []).map((f, i) => (i+1) + '. ' + f).join('
');
  const recos = (r.recommendations || []).map(rec => '• ' + rec).join('
');
  message = header + '
📄 *' + d.file_name + '*
🤖 Grok AI

📋 *' + (isFR ? "Vue d'ensemble" : 'Overview') + '*
' + (overview.rows || '?') + ' lignes · ' + (overview.columns || '?') + ' colonnes · Qualité : ' + (overview.data_quality || '?') + '/10

✨ *' + (isFR ? 'Résumé Exécutif' : 'Executive Summary') + '*
' + (r.executive_summary || '') + '

🔑 *' + (isFR ? 'Points Clés' : 'Key Findings') + '*
' + findings + '

💡 *' + (isFR ? 'Recommandations' : 'Recommendations') + '*
' + recos + '

⏱ _' + d.response_time_ms + 'ms · Grok AI_';
} else {
  const header = isFR ? '📄 *ANALYSE DU DOCUMENT*' : '📄 *DOCUMENT ANALYSIS*';
  const points = (r.key_points || []).map((p, i) => (i+1) + '. ' + p).join('
');
  const insights = (r.insights || []).map(ins => '💡 ' + ins).join('
');
  message = header + '
📄 *' + d.file_name + '*
🤖 Grok AI

✨ *' + (isFR ? 'Résumé Exécutif' : 'Executive Summary') + '*
' + (r.executive_summary || '') + '

🔑 *' + (isFR ? 'Points Clés' : 'Key Points') + '*
' + points + '

🔍 *Insights*
' + insights + '

🎯 *' + (isFR ? 'Public Cible' : 'Target Audience') + '*
' + (r.target_audience || 'Non déterminé') + ' · Qualité : ' + (r.quality_score || '?') + '/10

⏱ _' + d.response_time_ms + 'ms_';
}

if (message.length > 4096) message = message.substring(0, 4090) + '..._';

return [{
  json: {
    ...d,
    report_message: message,
    charts: r.charts || []
  }
}];

const d = $input.first().json;
const charts = d.charts || [];
const extractedData = d.extracted_data;

if (d.content_type !== 'data' || !charts.length || !extractedData || !extractedData.data) {
  return [{ json: { ...d, chart_urls: [], charts_count: 0 } }];
}

const rows = extractedData.data || [];
const cols = extractedData.columns || [];
const chartUrls = [];

for (const chart of charts.slice(0, 3)) {
  const type = chart.type || 'bar';
  const xCol = chart.x || cols[0];
  const yCol = chart.y || cols[1];
  if (!xCol || !yCol) continue;
  const xValues = rows.map(r => r[xCol]).filter(v => v != null).slice(0, 20);
  const yValues = rows.map(r => parseFloat(r[yCol])).filter(v => !isNaN(v)).slice(0, 20);
  if (!xValues.length || !yValues.length) continue;
  const chartConfig = {
    type: type,
    data: {
      labels: type !== 'scatter' ? xValues.map(String) : undefined,
      datasets: [{
        label: yCol,
        data: type === 'scatter' ? xValues.map((x, i) => ({ x, y: yValues[i] })) : yValues,
        backgroundColor: 'rgba(99, 102, 241, 0.5)',
        borderColor: 'rgba(99, 102, 241, 1)',
        borderWidth: 2,
        fill: false,
        tension: 0.3
      }]
    },
    options: {
      plugins: { title: { display: true, text: chart.title || (yCol + ' par ' + xCol) } }
    }
  };
  const encodedConfig = encodeURIComponent(JSON.stringify(chartConfig));
  chartUrls.push({
    url: 'https://quickchart.io/chart?c=' + encodedConfig + '&w=700&h=400&bkg=white',
    title: chart.title || '',
    insight: chart.insight || ''
  });
}

return [{ json: { ...d, chart_urls: chartUrls, charts_count: chartUrls.length } }];

// Prépare les paramètres pour UPDATE sessions
// Connecté depuis Generate Chart URLs (avant le chemin optionnel des charts)
// Suit le pattern CLAUDE.md : nodes critiques connectés en AMONT du node optionnel
const d = $input.first().json;

return [{
  json: {
    p1: d.llm_used || 'grok',
    p2: Buffer.from(JSON.stringify(d.analysis || {})).toString('base64'),
    p3: String(Math.round(d.response_time_ms || 0)),
    p4: String(d.session_id),
    chat_id: d.chat_id,
    language: d.language,
    session_id: d.session_id
  }
}];

// Chemin optionnel : split les graphiques pour envoi individuel
// Pattern CLAUDE.md : ce node peut retourner [] sans bloquer Update Session / Send Final Menu
const d = $input.first().json;
const charts = d.chart_urls || [];

if (!charts.length) {
  return [];
}

return charts.map(chart => ({
  json: {
    chat_id: d.chat_id,
    photo_url: chart.url,
    caption: '📊 ' + chart.title + '\n_' + chart.insight + '_'
  }
}));
